// Configure Prism autoloader to load languages from CDN
const plugins = Prism.plugins as Record<string, Record<string, unknown>>;
plugins["autoloader"]["languages_path"] =
  "https://cdn.jsdelivr.net/npm/prismjs@1.29.0/components/";

// Configure marked
marked.setOptions({ gfm: true, breaks: true });

// Mermaid state
let mermaidId = 0;
const mermaidDefinitions: string[] = [];

function currentThemeIsDark(): boolean {
  return document.documentElement.getAttribute("data-theme") === "dark";
}

// Initialize mermaid
mermaid.initialize({
  startOnLoad: false,
  theme: currentThemeIsDark() ? "dark" : "default",
  securityLevel: "loose",
  fontFamily: "var(--font-sans)",
});

// --- Math pre-processing ---

const mathPlaceholders: MathPlaceholder[] = [];

function protectMath(md: string): string {
  mathPlaceholders.length = 0;
  let idx = 0;

  // Block math: $$...$$
  md = md.replace(/\$\$([\s\S]+?)\$\$/g, (_, tex: string) => {
    const id = `%%MATH_BLOCK_${idx++}%%`;
    mathPlaceholders.push({ id, tex: tex.trim(), displayMode: true });
    return id;
  });

  // Inline math: $...$
  md = md.replace(/(?<!\$)\$(?!\$)(.+?)(?<!\$)\$(?!\$)/g, (_, tex: string) => {
    const id = `%%MATH_INLINE_${idx++}%%`;
    mathPlaceholders.push({ id, tex: tex.trim(), displayMode: false });
    return id;
  });

  return md;
}

function restoreMath(html: string): string {
  for (const { id, tex, displayMode } of mathPlaceholders) {
    try {
      const rendered = katex.renderToString(tex, {
        displayMode,
        throwOnError: false,
        trust: true,
      });
      html = html.replace(id, rendered);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      html = html.replace(
        id,
        `<span class="math-error" title="${escapeHtml(message)}">${escapeHtml(tex)}</span>`,
      );
    }
  }
  return html;
}

// --- Mermaid pre-processing ---
// Store raw mermaid definitions before the HTML pipeline (marked → DOMPurify)
// can corrupt them. Uses the stored originals at render time instead of DOM textContent.

function protectMermaid(md: string): void {
  mermaidDefinitions.length = 0;
  const re = /```mermaid\n([\s\S]*?)```/g;
  let match;
  while ((match = re.exec(md)) !== null) {
    mermaidDefinitions.push(match[1].trim());
  }
}

